CQ12.sparql:
PREFIX co: <http://cyberonto.org/ontology#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT (COUNT(?vuln) AS ?unmitigatedCount)
WHERE {
  ?vuln rdf:type co:CVE .
  OPTIONAL { ?vuln co:hasMitigation ?mit . }
  FILTER(!BOUND(?mit))
}
